<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'
import { ApiError, apiRequest, authState } from '../auth'
import type { Campaign, CampaignSubmission, MarketingForm } from '../marketing'
import AppShell from '../components/AppShell.vue'

const forms = ref<MarketingForm[]>([]); const campaigns = ref<Campaign[]>([]); const submissions = ref<CampaignSubmission[]>([]); const selected = ref<Campaign | null>(null); const error = ref(''); const message = ref('')
const canManage = computed(() => authState.user?.permissions.includes('marketing.manage') ?? false); const canExport = computed(() => authState.user?.permissions.includes('marketing.export') ?? false)
const form = reactive({ name: '', privacy_notice: '我同意企业为本次活动联系而处理所提交的信息。', success_message: '报名成功，我们会尽快与您联系。', fields_text: 'name|姓名|text|required\ncontact|联系方式|text|required\ndemand|需求说明|textarea' })
const campaign = reactive({ form_id: '', name: '', slug: '', description: '', card_id: '', product_id: '', owner_employee_id: '', channel: 'direct', starts_at: '', ends_at: '', capacity: '' })
async function load() { try { [forms.value, campaigns.value] = await Promise.all([apiRequest<MarketingForm[]>('/tenant/marketing/forms'), apiRequest<Campaign[]>('/tenant/marketing/campaigns')]) } catch (e) { error.value = e instanceof ApiError ? e.message : '营销数据加载失败' } }
function parsedFields() { return form.fields_text.split('\n').filter(Boolean).map(line => { const [key, label, type = 'text', required = ''] = line.split('|'); return { key: key.trim(), label: label.trim(), type: type.trim(), required: required.trim() === 'required', options: [] } }) }
async function saveForm() { try { await apiRequest('/tenant/marketing/forms', { method: 'POST', body: JSON.stringify({ name: form.name, fields: parsedFields(), privacy_notice: form.privacy_notice, success_message: form.success_message, is_active: true }) }); message.value = '表单已创建'; form.name = ''; await load() } catch (e) { error.value = e instanceof ApiError ? e.message : '表单保存失败' } }
async function saveCampaign() { const optional = (value: string) => value || null; try { await apiRequest('/tenant/marketing/campaigns', { method: 'POST', body: JSON.stringify({ ...campaign, card_id: optional(campaign.card_id), product_id: optional(campaign.product_id), owner_employee_id: optional(campaign.owner_employee_id), description: optional(campaign.description), capacity: campaign.capacity ? Number(campaign.capacity) : null, starts_at: new Date(campaign.starts_at).toISOString(), ends_at: new Date(campaign.ends_at).toISOString() }) }); message.value = '活动已创建'; await load() } catch (e) { error.value = e instanceof ApiError ? e.message : '活动创建失败' } }
async function action(item: Campaign, name: 'publish' | 'close') { await apiRequest(`/tenant/marketing/campaigns/${item.id}/${name}`, { method: 'POST' }); await load() }
async function openSubmissions(item: Campaign) { selected.value = item; const page = await apiRequest<{ items: CampaignSubmission[] }>(`/tenant/marketing/campaigns/${item.id}/submissions`); submissions.value = page.items }
async function setSubmission(item: CampaignSubmission, actionName: 'convert' | 'invalid') { await apiRequest(`/tenant/marketing/submissions/${item.id}/${actionName}`, { method: 'POST' }); if (selected.value) await openSubmissions(selected.value) }
async function download() { if (!selected.value || !authState.accessToken) return; const response = await fetch(`${import.meta.env.VITE_API_BASE_URL ?? 'http://localhost:8000/api/v1'}/tenant/marketing/campaigns/${selected.value.id}/export`, { headers: { Authorization: `Bearer ${authState.accessToken}` } }); const url = URL.createObjectURL(await response.blob()); const a = document.createElement('a'); a.href = url; a.download = `${selected.value.slug}.csv`; a.click(); URL.revokeObjectURL(url) }
onMounted(load)
</script>

<template><AppShell><header class="page-header compact"><div><p class="eyebrow">MARKETING</p><h1>营销表单与活动</h1><p>配置报名表单、发布活动，并把有效报名转为销售线索。</p></div></header><div v-if="message" class="notice success">{{ message }}</div><div v-if="error" class="notice error">{{ error }}</div><section v-if="canManage" class="settings-grid"><form class="panel form-stack" @submit.prevent="saveForm"><h2>新建表单</h2><label><span>表单名称</span><input v-model.trim="form.name" required /></label><label><span>字段（每行：键|名称|类型|required）</span><textarea v-model="form.fields_text" rows="5" required /></label><label><span>隐私说明</span><textarea v-model="form.privacy_notice" required /></label><label><span>提交结果提示</span><input v-model.trim="form.success_message" required /></label><button class="primary-button">保存表单</button></form><form class="panel form-stack" @submit.prevent="saveCampaign"><h2>新建活动</h2><label><span>表单</span><select v-model="campaign.form_id" required><option value="">请选择</option><option v-for="item in forms" :key="item.id" :value="item.id">{{ item.name }} · R{{ item.revision }}</option></select></label><label><span>活动名称</span><input v-model.trim="campaign.name" required /></label><label><span>公开地址标识</span><input v-model.trim="campaign.slug" pattern="[a-z0-9-]+" required /></label><div class="modal-grid"><label><span>开始时间</span><input v-model="campaign.starts_at" type="datetime-local" required /></label><label><span>结束时间</span><input v-model="campaign.ends_at" type="datetime-local" required /></label><label><span>人数限制</span><input v-model="campaign.capacity" type="number" min="1" /></label><label><span>分享渠道</span><input v-model.trim="campaign.channel" required /></label></div><label><span>名片 ID / 负责人 ID（转线索时必填）</span><input v-model.trim="campaign.card_id" placeholder="名片 ID" /><input v-model.trim="campaign.owner_employee_id" placeholder="负责人 ID" /></label><button class="primary-button">创建活动</button></form></section><section class="panel table-panel"><h2>活动列表</h2><div v-if="!campaigns.length" class="empty-state">暂无活动</div><table v-else><thead><tr><th>活动</th><th>时间/渠道</th><th>报名</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="item in campaigns" :key="item.id"><td><b>{{ item.name }}</b><small>/campaign/{{ item.slug }}</small></td><td>{{ item.channel }}</td><td>{{ item.submission_count }}{{ item.capacity ? ` / ${item.capacity}` : '' }}</td><td>{{ item.status }}</td><td class="actions"><button class="link-button" @click="openSubmissions(item)">报名名单</button><button v-if="canManage && item.status !== 'published'" class="link-button" @click="action(item, 'publish')">发布</button><button v-if="canManage && item.status === 'published'" class="link-button danger" @click="action(item, 'close')">关闭</button></td></tr></tbody></table></section><section v-if="selected" class="panel table-panel"><div class="section-heading"><h2>{{ selected.name }} · 报名名单</h2><button v-if="canExport" class="secondary-button" @click="download">导出 CSV</button></div><table><thead><tr><th>提交内容</th><th>渠道</th><th>表单版本</th><th>状态</th><th>线索</th><th v-if="canManage">操作</th></tr></thead><tbody><tr v-for="item in submissions" :key="item.id"><td>{{ Object.entries(item.values).map(([k,v]) => `${k}: ${v}`).join('；') }}</td><td>{{ item.channel }}</td><td>R{{ item.form_revision }}</td><td>{{ item.status }}</td><td>{{ item.lead_id || '—' }}</td><td v-if="canManage" class="actions"><button v-if="item.status === 'submitted'" class="link-button" @click="setSubmission(item, 'convert')">转为线索</button><button v-if="item.status === 'submitted'" class="link-button danger" @click="setSubmission(item, 'invalid')">无效</button></td></tr></tbody></table></section></AppShell></template>
